360	static json render_message_to_json(const std::vector<common_chat_msg> & msgs, const jinja::caps & c) {
361	    if (!c.supports_string_content && !c.supports_typed_content) {
362	        LOG_WRN("%s: Neither string content nor typed content is supported by the template. This is unexpected and may lead to issues.\n", __func__);
363	    }
364	
365	    bool only_string_accepted =  c.supports_string_content && !c.supports_typed_content;
366	    bool only_typed_accepted  = !c.supports_string_content &&  c.supports_typed_content;
367	
368	    json messages = json::array();
369	    for (const auto & msg : msgs) {
370	        if (only_string_accepted) {
371	            json jmsg = msg.to_json_oaicompat(/* concat_typed_text= */ true);
372	            messages.push_back(jmsg);
373	        } else if (only_typed_accepted) {
374	            json jmsg = msg.to_json_oaicompat(/* concat_typed_text= */ false);
375	            if (jmsg.at("content").is_string()) {
376	                jmsg["content"] = json::array({
377	                    json{
378	                        {"type", "text"},
379	                        {"text", jmsg.at("content").get<std::string>()},
380	                    }
381	                });
382	            }
383	            messages.push_back(jmsg);
384	        } else {
385	            json jmsg = msg.to_json_oaicompat(/* concat_typed_text= */ false);
386	            messages.push_back(jmsg);
387	        }
388	    }
389	    return messages;
390	}
