### 3. HOW `common_chat_try_specialized_template()` WORKS (Lines 1634-1691)

The function uses **marker-based detection** by searching for unique strings in the Jinja template source:

```cpp
std::optional<common_chat_params> common_chat_try_specialized_template(
        const common_chat_template & tmpl,
        const std::string & src,                    // Jinja template source code
        const autoparser::generation_params & params) {

    // Ministral/Mistral Large 3 - search for specific token markers
    // Note: Mistral Small 3.2 uses [CALL_ID] which Ministral doesn't have
    if (src.find("[SYSTEM_PROMPT]") != std::string::npos && 
        src.find("[TOOL_CALLS]") != std::string::npos &&
        src.find("[ARGS]") != std::string::npos && 
        src.find("[CALL_ID]") == std::string::npos) {  // Negative check to differentiate
        LOG_DBG("Using specialized template: Ministral/Magistral Large 3\n");
        return common_chat_params_init_ministral_3(tmpl, params);
    }

    // GPT-OSS - unique channel-based structure
    if (src.find("<|channel|>") != std::string::npos) {
        LOG_DBG("Using specialized template: GPT-OSS\n");
        return common_chat_params_init_gpt_oss(tmpl, params);
    }

    // Functionary v3.2 - recipient-based format
    if (src.find(">>>all") != std::string::npos && 
        src.find(">>>${recipient}") != std::string::npos) {
        LOG_DBG("Using specialized template: Functionary v3.2\n");
        return common_chat_params_init_functionary_v3_2(tmpl, params);
    }

    // Kimi K2 Thinking - unique tool call ID format
    if (src.find("<|tool_calls_section_begin|>") != std::string::npos &&
        src.find("<|tool_call_begin|>") != std::string::npos) {
        LOG_DBG("Using specialized template: Kimi K2 Thinking\n");
        return common_chat_params_init_kimi_k2(tmpl, params);
    }

    // LFM2 format detection
    if (src.find("<|tool_list_start|>") != std::string::npos &&
        src.find("<|tool_list_end|>") != std::string::npos) {
        LOG_DBG("Using specialized template: LFM2\n");
        return common_chat_params_init_lfm2(tmpl, params);
    }

    // LFM2.5 format detection (plain text)
    if (src.find("List of tools: [") != std::string::npos &&
        src.find("<|tool_list_start|>") == std::string::npos) {
        LOG_DBG("Using specialized template: LFM2.5\n");
        return common_chat_params_init_lfm2_5(tmpl, params);
    }

    // GigaChatV3 format detection
    if (src.find("<|role_sep|>") != std::string::npos &&
        src.find("<|message_sep|>") != std::string::npos &&
        src.find("<|function_call|>") == std::string::npos) {
        LOG_DBG("Using specialized template: GigaChatV3\n");
        return common_chat_params_init_gigachat_v3(tmpl, params);
    }

    return std::nullopt;  // No specialized handler matched
}
```

**Key Pattern**: Each handler checks for 1-3 unique marker strings. Multiple positive checks with negative checks (== std::string::npos) ensure precise template identification.

