### 6. HOW THE PROMPT IS GENERATED: `common_chat_template_direct_apply_impl()` (Lines 767-816)

```cpp
static std::string common_chat_template_direct_apply_impl(
    const common_chat_template & tmpl,
    const autoparser::generation_params & inputs,
    const std::optional<json> & messages_override = std::nullopt,
    const std::optional<json> & tools_override = std::nullopt,
    const std::optional<json> & additional_context = std::nullopt) {

    jinja::context ctx(tmpl.source());

    // Build the Jinja context object
    nlohmann::ordered_json inp = nlohmann::ordered_json{
        {"messages", messages_override.has_value() ? *messages_override : inputs.messages},
        {"bos_token", tmpl.bos_token()},
        {"eos_token", tmpl.eos_token()},
        {"enable_thinking", inputs.enable_thinking},
    };

    // Add tools if present
    if (tools_override.has_value() || !inputs.tools.empty()) {
        inp["tools"] = tools_override.has_value() ? *tools_override : inputs.tools;
    }

    // Merge extra context
    if (inputs.extra_context.is_object()) {
        for (const auto & [k, v] : inputs.extra_context.items()) {
            inp[k] = v;
        }
    }

    if (additional_context.has_value()) {
        for (const auto & [k, v] : additional_context->items()) {
            inp[k] = v;
        }
    }

    if (inputs.add_generation_prompt) {
        inp["add_generation_prompt"] = true;
    }

    // Load JSON into Jinja context
    jinja::global_from_json(ctx, inp, inputs.mark_input);

    // Execute the Jinja template
    jinja::runtime runtime(ctx);
    const jinja::value results = runtime.execute(tmpl.prog);
    auto parts = jinja::runtime::gather_string_parts(results);

    std::string result = parts->as_string().str();

    // Optional BOS/EOS token handling
    if (inputs.add_bos && string_starts_with(result, tmpl.bos_token())) {
        result = result.substr(tmpl.bos_token().size());
    }
    if (inputs.add_eos && string_ends_with(result, tmpl.eos_token())) {
        result = result.substr(0, result.size() - tmpl.eos_token().size());
    }
    return result;  // The formatted prompt!
}
```

**Key Points**:
- **Message transformation**: handlers often override `inputs.messages` with `adjusted_messages`
- **Jinja execution**: The template source (`tmpl.prog`) is executed with the JSON context
- **String assembly**: Messages are converted to JSON, tools are included as JSON, context variables are added

